nextGeneration(): [number, number][] {
  if (this.cells.length === 0) {
    return [];
  }

  const [x, y] = this.cells[0];
  const neighbors = this.countNeighbors(x, y);
  const result: [number, number][] = [];

  // Check survival of first cell
  if (
    neighbors >= GameOfLife.MIN_SURVIVAL_NEIGHBORS &&
    neighbors <= GameOfLife.MAX_SURVIVAL_NEIGHBORS
  ) {
    result.push([x, y]);
  }

  // Check (5, 5) for resurrection (minimal for reproduction test)
  if (!this.cellExists(5, 5)) {
    if (this.countNeighbors(5, 5) === 3) {
      result.push([5, 5]);
    }
